mapper.select:
SELECT
CASE WHEN SUM(s.nums)=0 THEN NULL ELSE ROUND(SUM(s.bct)/SUM(s.nums),4) END AS price,
SUM(s.nums) AS nums,
SUM(s.bct) AS total
FROM summary s

    s.goods = #{goodsId}
    AND s.warehouse = #{warehouseId}
    AND s.type = 'buy'
    AND s.time >= #{startTime}
    AND s.time < DATE_ADD(#{endTime}, INTERVAL 1 DAY)

